import React, { useEffect, useState, useMemo, useCallback, useRef } from "react";
import { Routes, Route, useNavigate, Navigate, useLocation } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import CryptoJS from "crypto-js";

// --- Constants ---
const APP_FOLDER_NAME = "MyBookmarksApp";
const ATTACHMENTS_FOLDER_NAME = "attachments";
const BOOKMARKS_FILE_NAME = "bookmarks.json";
const INITIAL_DATA_STRUCTURE = { folders: [], bookmarks: [] };

// --- Animation Variants ---
const containerVariants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.06, delayChildren: 0.05 } },
};
const itemVariants = {
  hidden: { y: 24, opacity: 0, scale: 0.97 },
  visible: { y: 0, opacity: 1, scale: 1, transition: { type: "spring", damping: 20, stiffness: 260 } },
};




function LoginPage() {
  const CLIENT_ID = process.env.REACT_APP_GOOGLE_CLIENT_ID;

  useEffect(() => {
    if (!window.google) {
      const script = document.createElement("script");
      script.src = "https://accounts.google.com/gsi/client";
      script.async = true;
      script.defer = true;
      document.body.appendChild(script);
    }
  }, []);

  const handleLogin = async () => {
    if (!CLIENT_ID) {
      alert(
        "Google CLIENT_ID is missing. Please check your .env file and restart the dev server."
      );
      return;
    }
    if (!window.google || !window.google.accounts) {
      alert("Google's GSI library not loaded yet.");
      return;
    }
    const tokenClient = window.google.accounts.oauth2.initTokenClient({
      client_id: CLIENT_ID,
      scope:
        "https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/userinfo.profile https://www.googleapis.com/auth/userinfo.email",
      callback: async (tokenResponse) => {
        if (tokenResponse && tokenResponse.access_token) {
          localStorage.setItem("accessToken", tokenResponse.access_token);
          try {
            const userInfoResponse = await fetch(
              "https://www.googleapis.com/oauth2/v3/userinfo",
              {
                headers: {
                  Authorization: `Bearer ${tokenResponse.access_token}`,
                },
              }
            );
            if (!userInfoResponse.ok) throw new Error("Failed to fetch user info");
            const userObject = await userInfoResponse.json();
            localStorage.setItem("user", JSON.stringify(userObject));
            // Use react-router navigate helper exposed on window for now
            if (typeof window.__navigate === "function") window.__navigate("/");
            else if (typeof window !== "undefined") window.location.hash = "#/";
          } catch (e) {
            alert("Login failed: " + e.message);
          }
        }
      },
    });
    tokenClient.requestAccessToken();
  };

  return (
    <div className="login-container">
      <div className="login-bg-orb login-bg-orb--1"></div>
      <div className="login-bg-orb login-bg-orb--2"></div>
      <div className="login-content">
        <div className="login-card">
          <div className="login-card__icon">
            <i className="fas fa-bookmark"></i>
          </div>
          <h2 className="login-card__title">Sign in to Drive Genie</h2>
          <p className="login-card__subtitle">
            Your bookmarks, encrypted and powered by Google Drive.
          </p>
          <div className="google-button-container">
            <button className="continue-btn" onClick={handleLogin}>
              <i className="fab fa-google"></i> Sign in with Google
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function RequireAuth({ children }) {
  const user = localStorage.getItem('user');
  const location = useLocation();
  if (!user) return <Navigate to="/login" state={{ from: location }} replace />;
  return children;
}

export default function App() {
  return (
    <Routes>
      <Route path="/login" element={<LoginPage />} />
      <Route
        path="/"
        element={
          <RequireAuth>
            <Dashboard />
          </RequireAuth>
        }
      />
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}

function Dashboard() {
  const navigate = useNavigate();


  const [user, setUser] = useState(null);
  const [bookmarks, setBookmarks] = useState([]);
  const [folders, setFolders] = useState([]);
  const [bookmarksFileId, setBookmarksFileId] = useState(null);
  const [storageInfo, setStorageInfo] = useState({
    used: 0,
    limit: 0,
    percent: 0,
  });
  const [attachmentsFolderId, setAttachmentsFolderId] = useState(null);
  const [selectedFolder, setSelectedFolder] = useState("all");
  const [folderSearchQuery, setFolderSearchQuery] = useState("");
  const [bookmarkSearchQuery, setBookmarkSearchQuery] = useState("");
  const [sortOrder, setSortOrder] = useState("newest");
  const [viewMode, setViewMode] = useState("grid");
  const [gridSize, setGridSize] = useState("small");
  const [isGapiReady, setIsGapiReady] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [error, setError] = useState(null);
  const gapiInitStarted = useRef(false);
  const rawDriveData = useRef(null);
  const fileViewerRef = useRef(null);


  const [masterPassword, setMasterPassword] = useState("");
  const [isVaultLocked, setIsVaultLocked] = useState(true);
  const [isPasswordModalOpen, setIsPasswordModalOpen] = useState(false);
  const [passwordModalMode, setPasswordModalMode] = useState("unlock");
  const [passwordInput, setPasswordInput] = useState("");
  const [passwordError, setPasswordError] = useState("");
  const [isFullscreen, setIsFullscreen] = useState(false);


  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState(null);
  const [modalTitle, setModalTitle] = useState("");
  const [modalFields, setModalFields] = useState([]);
  const [currentItem, setCurrentItem] = useState(null);
  const [newlySelectedFiles, setNewlySelectedFiles] = useState([]);
  const [existingAttachments, setExistingAttachments] = useState([]);
  const [modalSelectedFolderId, setModalSelectedFolderId] = useState("none");
  const [isFileViewerOpen, setIsFileViewerOpen] = useState(false);
  const [fileViewerContent, setFileViewerContent] = useState({
    type: null,
    data: null,
    name: "",
    width: null,
    height: null,
  });
  const [isConfirmationModalOpen, setIsConfirmationModalOpen] = useState(false);
  const [confirmationModalConfig, setConfirmationModalConfig] = useState({
    title: "",
    text: "",
    onConfirm: () => {},
  });
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deletionProgress, setDeletionProgress] = useState(0);
  const [deletionMessage, setDeletionMessage] = useState("");
  const [alertModal, setAlertModal] = useState({
    show: false,
    title: "",
    text: "",
  });
  const [isChangePasswordModalOpen, setIsChangePasswordModalOpen] = useState(false);
  const [currentPasswordInput, setCurrentPasswordInput] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [changePasswordError, setChangePasswordError] = useState("");


  const encryptData = (data, secretKey) => {
    const jsonString = JSON.stringify(data);
    return {
      encryptedData: CryptoJS.AES.encrypt(jsonString, secretKey).toString(),
    };
  };
  const decryptData = (encryptedPayload, secretKey) => {
    try {
      const bytes = CryptoJS.AES.decrypt(
        encryptedPayload.encryptedData,
        secretKey
      );
      const decryptedString = bytes.toString(CryptoJS.enc.Utf8);
      return decryptedString ? JSON.parse(decryptedString) : null;
    } catch (e) {
      return null;
    }
  };

  const isUrl = (str) => {
    if (typeof str !== "string") return false;
    return str.startsWith("http://") || str.startsWith("https://");
  };

  const timeAgo = (dateString) => {
    const seconds = Math.floor((Date.now() - new Date(dateString)) / 1000);
    if (seconds < 60) return "just now";
    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes}m ago`;
    const hours = Math.floor(minutes / 60);
    if (hours < 24) return `${hours}h ago`;
    const days = Math.floor(hours / 24);
    if (days < 30) return `${days}d ago`;
    const months = Math.floor(days / 30);
    if (months < 12) return `${months}mo ago`;
    return `${Math.floor(months / 12)}y ago`;
  };

  function formatBytes(bytes, decimals = 2) {
    if (bytes === 0) return "0 Bytes";
    const k = 1024;
    const dm = decimals < 0 ? 0 : decimals;
    const sizes = ["Bytes", "KB", "MB", "GB", "TB", "PB", "EB", "ZB", "YB"];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + " " + sizes[i];
  }

  // --- Core Google Drive Functions ---
  const handleLogout = useCallback(() => {
    const accessToken = localStorage.getItem("accessToken");
    if (accessToken)
      window.google?.accounts.oauth2.revoke(accessToken, () => {});
    localStorage.clear();
    navigate("/");
  }, [navigate]);

  const getAppFolderId = useCallback(async () => {
    const response = await window.gapi.client.drive.files.list({
      q: `mimeType='application/vnd.google-apps.folder' and name='${APP_FOLDER_NAME}' and trashed=false`,
      fields: "files(id)",
    });
    if (response.result.files?.length > 0) return response.result.files[0].id;
    const fileMetadata = {
      name: APP_FOLDER_NAME,
      mimeType: "application/vnd.google-apps.folder",
    };
    const folderResponse = await window.gapi.client.drive.files.create({
      resource: fileMetadata,
      fields: "id",
    });
    return folderResponse.result.id;
  }, []);

  const getOrCreateAttachmentsFolderId = useCallback(async (appFolderId) => {
    const response = await window.gapi.client.drive.files.list({
      q: `mimeType='application/vnd.google-apps.folder' and name='${ATTACHMENTS_FOLDER_NAME}' and '${appFolderId}' in parents and trashed=false`,
      fields: "files(id)",
    });
    if (response.result.files?.length > 0) return response.result.files[0].id;
    const fileMetadata = {
      name: ATTACHMENTS_FOLDER_NAME,
      mimeType: "application/vnd.google-apps.folder",
      parents: [appFolderId],
    };
    const folderResponse = await window.gapi.client.drive.files.create({
      resource: fileMetadata,
      fields: "id",
    });
    return folderResponse.result.id;
  }, []);

  const getOrCreateBookmarksFile = useCallback(async (appFolderId) => {
    const response = await window.gapi.client.drive.files.list({
      q: `'${appFolderId}' in parents and name='${BOOKMARKS_FILE_NAME}' and trashed=false`,
      fields: "files(id)",
    });
    if (response.result.files?.length > 0) return response.result.files[0].id;
    const fileMetadata = {
      name: BOOKMARKS_FILE_NAME,
      mimeType: "application/json",
      parents: [appFolderId],
    };
    const fileResponse = await window.gapi.client.drive.files.create({
      resource: fileMetadata,
      fields: "id",
    });
    return fileResponse.result.id;
  }, []);

  const updateBookmarksFileOnDrive = async (fileId, updatedData, passwordOverride) => {
    const password = passwordOverride || masterPassword;
    if (!fileId || !password) return;
    try {
      const encryptedPayload = encryptData(updatedData, password);
      const boundary = "-------314159265358979323846";
      const delimiter = `\r\n--${boundary}\r\n`,
        close_delim = `\r\n--${boundary}--`;
      const metadata = {
        name: BOOKMARKS_FILE_NAME,
        mimeType: "application/json",
      };
      const multipartRequestBody =
        delimiter +
        "Content-Type: application/json\r\n\r\n" +
        JSON.stringify(metadata) +
        delimiter +
        "Content-Type: application/json\r\n\r\n" +
        JSON.stringify(encryptedPayload) +
        close_delim;
      await window.gapi.client.request({
        path: `/upload/drive/v3/files/${fileId}`,
        method: "PATCH",
        params: { uploadType: "multipart" },
        headers: {
          "Content-Type": `multipart/related; boundary="${boundary}"`,
        },
        body: multipartRequestBody,
      });
    } catch (err) {
      console.error("Save Failed:", err);
    }
  };

  const uploadFileToDrive = (file, onProgress) => {
    return new Promise((resolve, reject) => {
      if (!attachmentsFolderId) {
        reject(new Error("Attachments folder not found."));
        return;
      }
      const metadata = {
        name: file.name,
        mimeType: file.type,
        parents: [attachmentsFolderId],
      };
      const form = new FormData();
      form.append(
        "metadata",
        new Blob([JSON.stringify(metadata)], { type: "application/json" })
      );
      form.append("file", file);
      const xhr = new XMLHttpRequest();
      xhr.open(
        "POST",
        "https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id"
      );
      xhr.setRequestHeader(
        "Authorization",
        "Bearer " + window.gapi.client.getToken().access_token
      );
      xhr.upload.onprogress = (event) => {
        if (event.lengthComputable && onProgress) {
          const percentComplete = Math.round(
            (event.loaded / event.total) * 100
          );
          onProgress(percentComplete);
        }
      };
      xhr.onload = () => {
        if (xhr.status === 200) {
          resolve(JSON.parse(xhr.responseText).id);
        } else {
          reject(new Error(`Upload failed with status: ${xhr.status}`));
        }
      };
      xhr.onerror = () => reject(new Error("Network error during upload."));
      xhr.send(form);
    });
  };

  const deleteFileFromDrive = async (fileId) => {
    if (!fileId) return;
    try {
      await window.gapi.client.drive.files.delete({ fileId });
    } catch (err) {
      if (err.result?.error)
        setAlertModal({
          show: true,
          title: "Deletion Failed",
          text: `Could not delete attachment. Reason: ${err.result.error.message}`,
        });
      else
        setAlertModal({
          show: true,
          title: "Deletion Failed",
          text: "An unknown error occurred.",
        });
    }
  };

  const refreshData = useCallback(async () => {
    if (!isGapiReady) return;
    setError(null);
    try {
      const appFolderId = await getAppFolderId();
      const attachFolderId = await getOrCreateAttachmentsFolderId(appFolderId);
      setAttachmentsFolderId(attachFolderId);
      const fileId = await getOrCreateBookmarksFile(appFolderId);
      setBookmarksFileId(fileId);
      try {
        const bookmarksResponse = await window.gapi.client.drive.files.get({
          fileId,
          alt: "media",
        });
        rawDriveData.current = bookmarksResponse.result;
      } catch (e) {
        rawDriveData.current = null;
      }
      const isNewVault =
        !rawDriveData.current || !rawDriveData.current.encryptedData;
      setPasswordModalMode(isNewVault ? "create" : "unlock");
      setPasswordError("");
      setPasswordInput("");
      setIsLoading(false);
      setIsPasswordModalOpen(true);
    } catch (err) {
      setError("Could not initialize application data. Please try refreshing.");
      setIsLoading(false);
    }
  }, [
    isGapiReady,
    getAppFolderId,
    getOrCreateAttachmentsFolderId,
    getOrCreateBookmarksFile,
  ]);

  const handlePasswordModalSubmit = async () => {
    setPasswordError("");
    if (!passwordInput) {
      setPasswordError("Password cannot be empty.");
      return;
    }
    const data = rawDriveData.current;
    const fetchAndSetStorageInfo = async () => {
      try {
        const response = await window.gapi.client.drive.about.get({
          fields: "storageQuota",
        });
        const quota = response.result.storageQuota;
        const used = parseInt(quota.usage, 10);
        const limit = parseInt(quota.limit, 10);

        setStorageInfo({
          used: used,
          limit: limit,
          percent: limit > 0 ? (used / limit) * 100 : 0,
        });
      } catch (err) {
        console.error("Could not fetch storage quota:", err);
      }
    };

    if (passwordModalMode === "unlock") {
      const decryptedData = decryptData(data, passwordInput);
      if (decryptedData) {
        setFolders(decryptedData.folders || []);
        setBookmarks(decryptedData.bookmarks || []);
        setMasterPassword(passwordInput);
        setIsVaultLocked(false);
        setIsPasswordModalOpen(false);
        await fetchAndSetStorageInfo();
      } else {
        setPasswordError("Incorrect password. Please try again.");
      }
    } else {
      const initialContent = data?.folders ? data : INITIAL_DATA_STRUCTURE;
      setFolders(initialContent.folders);
      setBookmarks(initialContent.bookmarks);
      setMasterPassword(passwordInput);
      setIsVaultLocked(false);
      setIsPasswordModalOpen(false);
      await updateBookmarksFileOnDrive(bookmarksFileId, initialContent);
      await fetchAndSetStorageInfo();
    }
    setPasswordInput("");
  };

  // --- Lifecycle Hooks ---
  useEffect(() => {
    const checkScreenSize = () => {
      if (window.innerWidth < 1024) setIsSidebarOpen(false);
      else setIsSidebarOpen(true);
    };
    checkScreenSize();
    window.addEventListener("resize", checkScreenSize);
    return () => window.removeEventListener("resize", checkScreenSize);
  }, []);

  useEffect(() => {
    const localUser = localStorage.getItem("user");
    const accessToken = localStorage.getItem("accessToken");
    if (!localUser || !accessToken) {
      navigate("/");
      return;
    }
    setUser(JSON.parse(localUser));
    if (gapiInitStarted.current || window.gapi) return;
    gapiInitStarted.current = true;
    const script = document.createElement("script");
    script.src = "https://apis.google.com/js/api.js";
    script.async = true;
    script.defer = true;
    script.onload = () => {
      window.gapi.load("client", async () => {
        try {
          await window.gapi.client.init({
            discoveryDocs: [
              "https://www.googleapis.com/discovery/v1/apis/drive/v3/rest",
            ],
          });
          window.gapi.client.setToken({ access_token: accessToken });
          setIsGapiReady(true);
        } catch (error) {
          setError(
            "Failed to initialize Google API. Please check your connection and refresh."
          );
          setIsLoading(false);
        }
      });
    };
    document.body.appendChild(script);
  }, [navigate]);

  useEffect(() => {
    if (isGapiReady) refreshData();
  }, [isGapiReady, refreshData]);

  useEffect(() => {
    const onFullscreenChange = () =>
      setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener("fullscreenchange", onFullscreenChange);
    return () =>
      document.removeEventListener("fullscreenchange", onFullscreenChange);
  }, []);


  // --- CRUD and UI Handlers ---
  const openModal = (mode, item = null) => {
    setModalMode(mode);
    setCurrentItem(item);
    setNewlySelectedFiles([]);
    if (mode === "addFolder" || mode === "renameFolder") {
      setModalTitle(
        mode === "addFolder" ? "Create New Folder" : "Rename Folder"
      );
      setModalFields([{ id: 1, title: "Name", value: item ? item.name : "" }]);
    } else if (mode === "addBookmark") {
      setModalTitle("Add New Bookmark");
      setModalFields([{ id: Date.now(), title: "Primary Title", value: "" }]);
      setModalSelectedFolderId(
        selectedFolder === "all" ? "none" : selectedFolder
      );
      setExistingAttachments([]);
    } else if (mode === "editBookmark") {
      setModalTitle("Edit Bookmark");
      setModalFields(
        item?.fields || [{ id: Date.now(), title: "Primary Title", value: "" }]
      );
      setModalSelectedFolderId(item?.folder_id || "none");
      setExistingAttachments(item?.attachments || []);
    }
    setIsModalOpen(true);
  };

  const handleModalFieldChange = (id, key, value) =>
    setModalFields((prevFields) =>
      prevFields.map((field) =>
        field.id === id ? { ...field, [key]: value } : field
      )
    );
  const addModalField = () =>
    setModalFields((prevFields) => [
      ...prevFields,
      { id: Date.now(), title: "", value: "" },
    ]);
  const removeModalField = (id) =>
    setModalFields((prevFields) =>
      prevFields.filter((field) => field.id !== id)
    );

  const handleModalSave = async () => {
    if (isVaultLocked) return;

    if (modalMode.includes("Folder")) {
      if (!modalFields[0]?.value.trim()) {
        setAlertModal({
          show: true,
          title: "Invalid Input",
          text: "Folder name cannot be empty.",
        });
        return;
      }
      const folderName = modalFields[0].value.trim();
      const optimisticFolders =
        modalMode === "addFolder"
          ? [...folders, { id: `folder_${Date.now()}`, name: folderName }]
          : folders.map((f) =>
              f.id === currentItem.id ? { ...f, name: folderName } : f
            );

      setFolders(optimisticFolders);
      setIsModalOpen(false);
      showToast(modalMode === "addFolder" ? "Folder created" : "Folder renamed", "success");
      await updateBookmarksFileOnDrive(bookmarksFileId, {
        folders: optimisticFolders,
        bookmarks,
      });
    } else {
      if (!modalFields[0]?.value.trim()) {
        setAlertModal({
          show: true,
          title: "Invalid Input",
          text: "The Primary Title field cannot be empty.",
        });
        return;
      }

      const newBookmarkData = {
        id:
          modalMode === "addBookmark"
            ? `bookmark_${Date.now()}`
            : currentItem.id,
        folder_id:
          modalSelectedFolderId === "none" ? null : modalSelectedFolderId,
        created_at:
          modalMode === "addBookmark"
            ? new Date().toISOString()
            : currentItem.created_at,
        fields: modalFields.filter((f) => f.title.trim() && f.value.trim()),
        attachments: [...existingAttachments], 
      };

      const optimisticBookmarks =
        modalMode === "addBookmark"
          ? [...bookmarks, newBookmarkData]
          : bookmarks.map((b) =>
              b.id === currentItem.id ? newBookmarkData : b
            );

      setBookmarks(optimisticBookmarks);
      setIsModalOpen(false);
      showToast(modalMode === "addBookmark" ? "Bookmark added" : "Bookmark updated", "success");

      (async () => {
        let finalAttachments = [...existingAttachments];
        if (newlySelectedFiles.length > 0) {
          setIsUploading(true);
          setUploadProgress(0);
          for (let i = 0; i < newlySelectedFiles.length; i++) {
            const file = newlySelectedFiles[i];
            const fileId = await uploadFileToDrive(file, (percent) => {
              const totalPercent = Math.round(
                ((i + percent / 100) / newlySelectedFiles.length) * 100
              );
              setUploadProgress(totalPercent);
            });
            finalAttachments.push({
              fileId,
              name: file.name,
              mimeType: file.type,
            });
          }
          setIsUploading(false);
        }

        const finalBookmarkData = {
          ...newBookmarkData,
          attachments: finalAttachments,
        };
        const finalBookmarks = optimisticBookmarks.map((b) =>
          b.id === finalBookmarkData.id ? finalBookmarkData : b
        );

        if (newlySelectedFiles.length > 0) {
          setBookmarks(finalBookmarks);
        }

        await updateBookmarksFileOnDrive(bookmarksFileId, {
          folders,
          bookmarks: finalBookmarks,
        });
      })();
    }
  };

  const openConfirmationModal = (config) => {
    setConfirmationModalConfig(config);
    setIsConfirmationModalOpen(true);
  };

  const handleDeleteFolder = (folderId, name) => {
    if (isVaultLocked) return;
    openConfirmationModal({
      title: "Delete Folder?",
      text: `This will permanently delete the folder "${name}" and all bookmarks inside. This action cannot be undone.`,
      onConfirm: async () => {
        setIsDeleting(true);
        setDeletionMessage("Deleting folder contents...");
        setDeletionProgress(0);

        try {
          const bookmarksInFolder = bookmarks.filter(
            (b) => b.folder_id === folderId
          );
          const allAttachmentsToDelete = bookmarksInFolder.flatMap(
            (b) => b.attachments || []
          );
          const totalItems = allAttachmentsToDelete.length;

          if (totalItems > 0) {
            for (let i = 0; i < totalItems; i++) {
              await deleteFileFromDrive(allAttachmentsToDelete[i].fileId);
              const progress = Math.round(((i + 1) / totalItems) * 100);
              setDeletionProgress(progress);
            }
          } else {
            setDeletionProgress(100);
          }

          setDeletionMessage("Finalizing deletion...");

          const updatedFolders = folders.filter((f) => f.id !== folderId);
          const updatedBookmarks = bookmarks.filter(
            (b) => b.folder_id !== folderId
          );
          await updateBookmarksFileOnDrive(bookmarksFileId, {
            folders: updatedFolders,
            bookmarks: updatedBookmarks,
          });

          setFolders(updatedFolders);
          setBookmarks(updatedBookmarks);
          setSelectedFolder("all");
          showToast("Folder deleted", "success");
        } catch (err) {
          console.error("Folder deletion error:", err);
          setAlertModal({
            show: true,
            title: "Error",
            text: "Failed to delete the folder.",
          });
        } finally {
          setIsDeleting(false);
        }
      },
    });
  };

  const handleDeleteBookmark = (id) => {
    const bookmarkToDelete = bookmarks.find((b) => b.id === id);
    if (!bookmarkToDelete) return;
    openConfirmationModal({
      title: "Delete Bookmark?",
      text: `Are you sure you want to permanently delete "${
        bookmarkToDelete.fields?.[0]?.value || "this bookmark"
      }"?`,
      onConfirm: async () => {
        setIsDeleting(true);
        setDeletionMessage("Deleting bookmark...");
        setDeletionProgress(0);

        try {
          const attachmentsToDelete = bookmarkToDelete.attachments || [];
          const totalItems = attachmentsToDelete.length;

          if (totalItems > 0) {
            for (let i = 0; i < totalItems; i++) {
              await deleteFileFromDrive(attachmentsToDelete[i].fileId);
              const progress = Math.round(((i + 1) / totalItems) * 100);
              setDeletionProgress(progress);
            }
          } else {
            setDeletionProgress(100);
          }

          const updatedBookmarks = bookmarks.filter((b) => b.id !== id);
          await updateBookmarksFileOnDrive(bookmarksFileId, {
            folders,
            bookmarks: updatedBookmarks,
          });
          setBookmarks(updatedBookmarks);
          showToast("Bookmark deleted", "success");
        } catch (err) {
          console.error("Deletion error:", err);
          setAlertModal({
            show: true,
            title: "Error",
            text: "Failed to delete the bookmark.",
          });
        } finally {
          setIsDeleting(false);
        }
      },
    });
  };

  const [toasts, setToasts] = useState([]);
  const showToast = (message, type = "success") => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 2500);
  };

  const [copiedFieldId, setCopiedFieldId] = useState(null);
  const handleCopy = (text, fieldId) => {
    navigator.clipboard.writeText(text);
    setCopiedFieldId(fieldId);
    showToast("Copied to clipboard", "success");
    setTimeout(() => setCopiedFieldId(null), 1200);
  };
  const handleFolderClick = (folderId) => {
    setSelectedFolder(folderId);
    if (window.innerWidth < 1024) setIsSidebarOpen(false);
  };
  const handleViewChange = (mode, size = "medium") => {
    setViewMode(mode);
    setGridSize(size);
  };

  // --- Filtering Logic ---
  const filteredFolders = useMemo(() => {
    if (!folderSearchQuery.trim()) {
      return folders;
    }
    const query = folderSearchQuery.toLowerCase().trim();
    return folders.filter((folder) =>
      folder.name.toLowerCase().includes(query)
    );
  }, [folders, folderSearchQuery]);

  const filteredData = useMemo(() => {
    let data = [...bookmarks];
    if (bookmarkSearchQuery.trim()) {
      const query = bookmarkSearchQuery.toLowerCase().trim();
      data = data.filter(
        (b) =>
          (b.fields || []).some(
            (f) =>
              f.title.toLowerCase().includes(query) ||
              f.value.toLowerCase().includes(query)
          ) ||
          (b.attachments || []).some((att) =>
            att.name.toLowerCase().includes(query)
          )
      );
    }
    if (selectedFolder !== "all")
      data = data.filter((b) => b.folder_id === selectedFolder);
    return data.sort(
      (a, b) =>
        new Date(sortOrder === "newest" ? b.created_at : a.created_at) -
        new Date(sortOrder === "newest" ? a.created_at : b.created_at)
    );
  }, [bookmarks, selectedFolder, bookmarkSearchQuery, sortOrder]);

  const handleViewFile = async (attachment) => {
    const { fileId, mimeType, name } = attachment;
    setFileViewerContent({ type: "loading", data: null, name });
    setIsFileViewerOpen(true);
    try {
      if (mimeType.startsWith("image/")) {
        const accessToken = window.gapi.client.getToken().access_token;
        const response = await fetch(
          `https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`,
          { headers: { Authorization: `Bearer ${accessToken}` } }
        );
        if (!response.ok) throw new Error("Failed to fetch image.");
        const imageBlob = await response.blob();
        setFileViewerContent({
          type: "image",
          data: URL.createObjectURL(imageBlob),
          name,
        });
      } else if (
        mimeType === "application/pdf" ||
        mimeType.startsWith("video/")
      ) {
        const { result } = await window.gapi.client.drive.files.get({
          fileId,
          fields: "webViewLink, videoMediaMetadata",
        });
        const width = result.videoMediaMetadata?.width || null;
        const height = result.videoMediaMetadata?.height || null;
        setFileViewerContent({
          type: "iframe",
          data: result.webViewLink.replace("/view", "/preview"),
          name,
          width,
          height,
        });
      } else if (mimeType.startsWith("text/")) {
        const response = await window.gapi.client.drive.files.get({
          fileId,
          alt: "media",
        });
        setFileViewerContent({ type: "text", data: response.body, name });
      } else {
        const { result } = await window.gapi.client.drive.files.get({
          fileId,
          fields: "webViewLink",
        });
        window.open(result.webViewLink, "_blank");
        setIsFileViewerOpen(false);
      }
    } catch (err) {
      setFileViewerContent({
        type: "error",
        data: "Could not load file preview.",
        name,
      });
    }
  };

  const handleDownloadFile = async (attachment) => {
    try {
      const { result } = await window.gapi.client.drive.files.get({
        fileId: attachment.fileId,
        fields: "webContentLink",
      });
      window.open(result.webContentLink, "_blank");
    } catch (err) {
      setAlertModal({
        show: true,
        title: "Error",
        text: "Could not get the download link for this file.",
      });
    }
  };

  const handleToggleFullscreen = () => {
    const elem = fileViewerRef.current;
    if (!elem) return;
    if (!document.fullscreenElement)
      elem.requestFullscreen().catch((err) => alert(`Error: ${err.message}`));
    else document.exitFullscreen();
  };

  const handleChangePassword = async () => {
    setChangePasswordError("");

    if (currentPasswordInput !== masterPassword) {
      setChangePasswordError("Incorrect current password.");
      return;
    }
    if (!newPassword) {
      setChangePasswordError("New password cannot be empty.");
      return;
    }
    if (newPassword !== confirmPassword) {
      setChangePasswordError("New passwords do not match.");
      return;
    }

    setIsDeleting(true);
    setDeletionMessage("Re-encrypting your vault...");
    setDeletionProgress(50);

    try {
      const currentData = { folders, bookmarks };
      await updateBookmarksFileOnDrive(bookmarksFileId, currentData, newPassword);
      setMasterPassword(newPassword);

      setIsChangePasswordModalOpen(false);
      setCurrentPasswordInput("");
      setNewPassword("");
      setConfirmPassword("");
      showToast("Password changed successfully", "success");
    } catch (err) {
      console.error("Failed to change password:", err);
      setChangePasswordError("An error occurred. Please try again.");
    } finally {
      setIsDeleting(false);
    }
  };

  if (isLoading)
    return (
      <div className="loading-screen">
        <i className="fas fa-bookmark loading-brand-icon"></i>
        <span>Loading vault...</span>
      </div>
    );

  if (error)
    return (
      <div className="loading-screen error-screen">
        <p>{error}</p>
        <button onClick={handleLogout}>Logout</button>
      </div>
    );

  return (
    <>
      {/* Toast Notifications */}
      <AnimatePresence>
        {toasts.length > 0 && (
          <div className="toast-container">
            {toasts.map(toast => (
              <motion.div
                key={toast.id}
                className={`toast toast--${toast.type}`}
                initial={{ opacity: 0, y: -20, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, y: -20, scale: 0.95 }}
                transition={{ type: "spring", damping: 20, stiffness: 300 }}
              >
                <i className={`toast__icon fas ${toast.type === 'success' ? 'fa-check-circle' : toast.type === 'error' ? 'fa-exclamation-circle' : 'fa-info-circle'}`}></i>
                <span className="toast__text">{toast.message}</span>
              </motion.div>
            ))}
          </div>
        )}
      </AnimatePresence>

      {!isVaultLocked ? (
        <div
          className={`aurora-layout ${isSidebarOpen ? "sidebar-is-open" : ""}`}
        >
          {isSidebarOpen && (
            <div
              className="sidebar-overlay"
              onClick={() => setIsSidebarOpen(false)}
            ></div>
          )}
          <aside className="sidebar">
            <h1 className="sidebar__header">Drive Genie</h1>
            <div className="sidebar__search-container">
              <i className="fas fa-search"></i>
              <input
                type="search"
                className="sidebar__search-input"
                placeholder="Search folders..."
                value={folderSearchQuery}
                onChange={(e) => setFolderSearchQuery(e.target.value)}
              />
            </div>
            <div className="sidebar__section">
              <span>Add New Folders</span>
              <button
                onClick={() => openModal("addFolder")}
                className="btn-add-folder"
                title="Add Folder"
                disabled={!bookmarksFileId}
              >
                <i className="fas fa-plus"></i>
              </button>
            </div>
            <ul className="folder-list">
              <li
                className={`folder-list__item ${
                  selectedFolder === "all" ? "folder-list__item--active" : ""
                }`}
                onClick={() => handleFolderClick("all")}
              >
                <i className="fas fa-globe-americas"></i>
                <span>All Bookmarks</span>
                <span className="folder-badge">{bookmarks.length}</span>
              </li>
              {filteredFolders.map((folder, index) => (
                <li
                  key={folder.id || index}
                  className={`folder-list__item ${
                    selectedFolder === folder.id
                      ? "folder-list__item--active"
                      : ""
                  }`}
                  onClick={() => handleFolderClick(folder.id)}
                >
                  <i className="fas fa-folder"></i>
                  <span>{folder.name}</span>
                  <span className="folder-badge">{bookmarks.filter(b => b.folder_id === folder.id).length}</span>
                  <div className="folder-item__actions">
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        openModal("renameFolder", folder);
                      }}
                      className="btn-icon-edit"
                      title="Rename Folder"
                    >
                      <i className="fas fa-pencil-alt"></i>
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDeleteFolder(folder.id, folder.name);
                      }}
                      className="btn-icon-delete"
                      title="Delete Folder"
                    >
                      <i className="fas fa-trash-alt"></i>
                    </button>
                  </div>
                </li>
              ))}
            </ul>
            <div className="sidebar__footer">
              <div className="storage-meter">
                <div className="storage-meter__header">
                  <i className="fas fa-hdd"></i>
                  <span>Drive Storage</span>
                </div>
                <div className="storage-meter__progress-bar">
                  <div
                    className="storage-meter__progress-fill"
                    style={{ width: `${storageInfo.percent}%` }}
                  ></div>
                </div>
                <div className="storage-meter__text">
                  <span>{formatBytes(storageInfo.used)}</span> /{" "}
                  {formatBytes(storageInfo.limit)}
                </div>
                <hr className="custom-divider" />
                <div className="user-profile-section">
                  <div className="user-info">
                    {user && (
                      <img
                        src={user.picture}
                        alt="User"
                        className="user-avatar"
                      />
                    )}
                    <span className="user-name">{user?.name}</span>
                  </div>
                  <div className="profile-actions">
                    <button
                      onClick={() => setIsChangePasswordModalOpen(true)}
                      className="btn-icon btn-change-password"
                      title="Change Master Password"
                    >
                      <i className="fas fa-key"></i>
                    </button>
                    <button
                      onClick={handleLogout}
                      className="btn-icon btn-logout"
                      title="Logout"
                    >
                      <i className="fas fa-sign-out-alt"></i>
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </aside>
          <main className="main-content">
            <div className="main-content__header">
              <button
                className="sidebar-toggle"
                onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              >
                <i className="fas fa-bars"></i>
              </button>
              <h2 className="main-content__title">
                {selectedFolder === "all"
                  ? "All Bookmarks"
                  : folders.find((f) => f.id === selectedFolder)?.name || "..."}
              </h2>
              <span className="bookmark-count">{filteredData.length} {filteredData.length === 1 ? 'item' : 'items'}</span>

              <div className="main-search-container">
                <i className="fas fa-search"></i>
                <input
                  type="search"
                  className="main-search-input"
                  placeholder="Search bookmarks..."
                  value={bookmarkSearchQuery}
                  onChange={(e) => setBookmarkSearchQuery(e.target.value)}
                />
              </div>

              <div className="controls">
                <button
                  onClick={() => openModal("addBookmark")}
                  className="control-btn-primary"
                >
                  <i className="fas fa-plus"></i> Add
                </button>
                <div className="control-group">
                  <button
                    onClick={() => setSortOrder("newest")}
                    className={`control-btn ${
                      sortOrder === "newest" ? "active" : ""
                    }`}
                    title="Sort Newest"
                  >
                    <i className="fas fa-sort-alpha-down"></i>
                  </button>
                  <button
                    onClick={() => setSortOrder("oldest")}
                    className={`control-btn ${
                      sortOrder === "oldest" ? "active" : ""
                    }`}
                    title="Sort Oldest"
                  >
                    <i className="fas fa-sort-alpha-up"></i>
                  </button>
                </div>
                <div className="control-group">
                  <button
                    onClick={() => handleViewChange("list")}
                    className={`control-btn ${
                      viewMode === "list" ? "active" : ""
                    }`}
                    title="List View"
                  >
                    <i className="fas fa-list"></i>
                  </button>
                  <button
                    onClick={() => handleViewChange("grid", "small")}
                    className={`control-btn ${
                      viewMode === "grid" && gridSize === "small"
                        ? "active"
                        : ""
                    }`}
                    title="Small Grid"
                  >
                    <i className="fas fa-th"></i>
                  </button>
                  <button
                    onClick={() => handleViewChange("grid", "medium")}
                    className={`control-btn ${
                      viewMode === "grid" && gridSize === "medium"
                        ? "active"
                        : ""
                    }`}
                    title="Medium Grid"
                  >
                    <i className="fas fa-th-large"></i>
                  </button>
                  <button
                    onClick={() => handleViewChange("grid", "large")}
                    className={`control-btn ${
                      viewMode === "grid" && gridSize === "large"
                        ? "active"
                        : ""
                    }`}
                    title="Large Grid"
                  >
                    <i className="fas fa-square"></i>
                  </button>
                </div>
              </div>
            </div>
            <hr className="custom-divider" />
            <AnimatePresence>
              <motion.div
                className={
                  viewMode === "grid"
                    ? `grid-container grid-size-${gridSize}`
                    : "list-container"
                }
                variants={containerVariants}
                initial="hidden"
                animate="visible"
                exit="hidden"
              >
                {filteredData.length > 0 ? (
                  filteredData.map((bookmark, index) => (
                    <motion.div
                      key={bookmark.id || bookmark.created_at || index}
                      variants={itemVariants}
                    >
                      <div className="smart-card">
                        <div className="smart-card__header">
                          <h5>{bookmark.fields?.[0]?.value || "Untitled"}</h5>
                          <p>
                            {bookmark.fields?.[0]?.title || "Primary Title"}
                          </p>
                        </div>
                        {bookmark.created_at && (
                          <div className="smart-card__timestamp">
                            <i className="far fa-clock"></i> {timeAgo(bookmark.created_at)}
                          </div>
                        )}
                        {bookmark.fields && bookmark.fields.length > 1 && (
                          <div className="smart-card__body">
                            {bookmark.fields
                              .slice(1)
                              .map((field, fieldIndex) => (
                                <div
                                  key={field.id || fieldIndex}
                                  className="card-field"
                                >
                                  <span className="card-field__title">
                                    {field.title}
                                  </span>
                                    <div className="card-field__value">
                                      <div className="card-field__actions">
                                        <button
                                          onClick={() => {
                                            const url = field.value.startsWith('http://') || field.value.startsWith('https://')
                                              ? field.value
                                              : `https://${field.value}`;
                                            window.open(url, '_blank', 'noopener,noreferrer');
                                          }}
                                          className="btn-icon-glass"
                                          title={`Open ${field.title} in browser`}
                                        >
                                          <i className="fas fa-external-link-alt"></i>
                                        </button>
                                        <button
                                          onClick={() => handleCopy(field.value, field.id || fieldIndex)}
                                          className={`btn-icon-copy ${copiedFieldId === (field.id || fieldIndex) ? 'copied' : ''}`}
                                          title={`Copy ${field.title}`}
                                        >
                                          <i className={copiedFieldId === (field.id || fieldIndex) ? "fas fa-check" : "far fa-copy"}></i>
                                          {copiedFieldId === (field.id || fieldIndex) && <span className="copy-feedback">Copied!</span>}
                                        </button>
                                      </div>
                                      {isUrl(field.value) ? (
                                        <a
                                          href={field.value}
                                          target="_blank"
                                          rel="noopener noreferrer"
                                          className="card-field__link"
                                        >
                                          <pre>{field.value}</pre>
                                        </a>
                                      ) : (
                                        <pre>{field.value}</pre>
                                      )}
                                    </div>
                                </div>
                              ))}
                          </div>
                        )}

                        {bookmark.attachments &&
                          bookmark.attachments.length > 0 && (
                            <div className="smart-card__attachment-list">
                              {bookmark.attachments.map((att) => (
                                <div
                                  key={att.fileId}
                                  className="smart-card__attachment"
                                >
                                  <i className="fas fa-paperclip"></i>
                                  <span>{att.name}</span>
                                  <div className="attachment-actions">
                                    <button
                                      onClick={() => handleViewFile(att)}
                                      title="View File"
                                    >
                                      <i className="fas fa-eye"></i>
                                    </button>
                                    <button
                                      onClick={() => handleDownloadFile(att)}
                                      title="Download File"
                                    >
                                      <i className="fas fa-download"></i>
                                    </button>
                                  </div>
                                </div>
                              ))}
                            </div>
                          )}

                        <div className="smart-card__footer">
                          <div className="smart-card__actions">
                            <button
                              onClick={() =>
                                openModal("editBookmark", bookmark)
                              }
                              className="btn-icon-edit-card"
                              title="Edit Bookmark"
                            >
                              <i className="fas fa-pencil-alt"></i>
                            </button>
                            <button
                              onClick={() => handleDeleteBookmark(bookmark.id)}
                              className="btn-icon-hover btn-icon-delete-hover"
                              title="Delete Bookmark"
                            >
                              <i className="fas fa-trash"></i>
                            </button>
                          </div>
                        </div>
                      </div>
                    </motion.div>
                  ))
                ) : (
                  <motion.div
                    className="no-bookmarks"
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                  >
                    <div className="empty-state-icon">
                      <i className="fas fa-bookmark"></i>
                    </div>
                    <p>No bookmarks yet</p>
                    <span className="empty-state-hint">Tap the + button to add your first bookmark</span>
                  </motion.div>
                )}
              </motion.div>
            </AnimatePresence>
            <button className="fab" onClick={() => openModal("addBookmark")} title="Add Bookmark">
              <i className="fas fa-plus"></i>
            </button>
          </main>
        </div>
      ) : (
        <div className="password-prompt-background"></div>
      )}

      <AnimatePresence>
        {isUploading && (
          <div className="modal-overlay" key="uploading-modal">
            <motion.div className="loading-modal-content" initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}>
              <div className="progress-ring">
                <svg viewBox="0 0 80 80">
                  <circle className="progress-ring__bg" cx="40" cy="40" r="35" />
                  <circle className="progress-ring__fill" cx="40" cy="40" r="35"
                    strokeDasharray={2 * Math.PI * 35}
                    strokeDashoffset={2 * Math.PI * 35 * (1 - uploadProgress / 100)} />
                </svg>
                <span className="progress-ring__text">{uploadProgress}%</span>
              </div>
              <p>Uploading file...</p>
            </motion.div>
          </div>
        )}

        {isDeleting && (
          <div className="modal-overlay" key="deleting-modal">
            <motion.div className="loading-modal-content" initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}>
              <div className="progress-ring">
                <svg viewBox="0 0 80 80">
                  <circle className="progress-ring__bg" cx="40" cy="40" r="35" />
                  <circle className="progress-ring__fill" cx="40" cy="40" r="35"
                    strokeDasharray={2 * Math.PI * 35}
                    strokeDashoffset={2 * Math.PI * 35 * (1 - deletionProgress / 100)} />
                </svg>
                <span className="progress-ring__text">{deletionProgress}%</span>
              </div>
              <p>{deletionMessage}</p>
            </motion.div>
          </div>
        )}

        {alertModal.show && (
          <div className="modal-overlay" key="alert-modal">
            <motion.div
              className="modal-content"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
            >
              <h3 className="modal-title">{alertModal.title}</h3>
              <div className="modal-body">
                <p className="modal-description">{alertModal.text}</p>
              </div>
              <div className="modal-footer">
                <button
                  className="modal-save-btn"
                  onClick={() =>
                    setAlertModal({ show: false, title: "", text: "" })
                  }
                >
                  Close
                </button>
              </div>
            </motion.div>
          </div>
        )}
        {isPasswordModalOpen && (
          <motion.div className="modal-overlay" key="password-modal" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            <motion.div
              className="modal-content"
              initial={{ y: 60, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              exit={{ y: 60, opacity: 0 }}
              transition={{ type: "spring", damping: 25, stiffness: 300 }}
            >
              <h3 className="modal-title">
                {passwordModalMode === "create"
                  ? "Create Master Password"
                  : "Unlock Your Vault"}
              </h3>
              <div className="modal-body">
                <p className="modal-description">
                  {passwordModalMode === "create"
                    ? "This password encrypts your data. Store it safely, it cannot be recovered."
                    : "Enter your master password to decrypt and access your data."}
                </p>
                <input
                  type="password"
                  className="modal-input"
                  placeholder="Enter master password..."
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  onKeyDown={(e) =>
                    e.key === "Enter" && handlePasswordModalSubmit()
                  }
                  autoFocus
                />
                {passwordError && (
                  <p className="modal-error">{passwordError}</p>
                )}
              </div>
              <div className="modal-footer">
                <button className="modal-cancel-btn" onClick={handleLogout}>
                  Logout
                </button>
                <button
                  className="modal-save-btn"
                  onClick={handlePasswordModalSubmit}
                >
                  {passwordModalMode === "create" ? "Create & Open" : "Unlock"}
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
        {isModalOpen && (
          <motion.div
            className="modal-overlay"
            key="add-edit-modal"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ scale: 0.9, opacity: 0 }}
            onClick={() => setIsModalOpen(false)}
          >
            <motion.div
              className="modal-content"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              onClick={(e) => e.stopPropagation()}
            >
              <h3 className="modal-title">{modalTitle}</h3>
              <div className="modal-body">
                {modalFields.map((field, index) => (
                  <div className="modal-field-row" key={field.id || index}>
                    <input
                      type="text"
                      className="modal-input modal-input--title"
                      value={field.title}
                      onChange={(e) =>
                        handleModalFieldChange(
                          field.id,
                          "title",
                          e.target.value
                        )
                      }
                      placeholder={`Field ${index + 1} Title`}
                    />
                    <textarea
                      className="modal-textarea"
                      value={field.value}
                      onChange={(e) =>
                        handleModalFieldChange(
                          field.id,
                          "value",
                          e.target.value
                        )
                      }
                      placeholder={`Field ${index + 1} Value`}
                      rows="1"
                    ></textarea>
                    {modalFields.length > 1 && (
                      <button
                        className="modal-remove-field-btn"
                        onClick={() => removeModalField(field.id)}
                      >
                        <i className="fas fa-times"></i>
                      </button>
                    )}
                  </div>
                ))}
                {(modalMode === "addBookmark" ||
                  modalMode === "editBookmark") && (
                  <button
                    className="modal-add-field-btn"
                    onClick={addModalField}
                  >
                    <i className="fas fa-plus"></i> Add Field
                  </button>
                )}
                {(modalMode === "addBookmark" ||
                  modalMode === "editBookmark") && (
                  <div className="modal-folder-selector-section">
                    <label className="input-section-label">Folder</label>
                    <select
                      className="modal-select"
                      value={modalSelectedFolderId}
                      onChange={(e) => setModalSelectedFolderId(e.target.value)}
                    >
                      <option value="none">Uncategorized</option>
                      {folders.map((folder) => (
                        <option key={folder.id} value={folder.id}>
                          {folder.name}
                        </option>
                      ))}
                    </select>
                  </div>
                )}
                {(modalMode === "addBookmark" ||
                  modalMode === "editBookmark") && (
                  <div className="modal-file-input-section">
                    <label className="input-section-label">Attachments</label>
                    {existingAttachments.length > 0 && (
                      <div className="attachment-list">
                        {existingAttachments.map((att) => (
                          <div
                            key={att.fileId}
                            className="attachment-list-item"
                          >
                            <i className="fas fa-file"></i>
                            <span>{att.name}</span>
                            <button
                              onClick={async () => {
                                await deleteFileFromDrive(att.fileId);
                                setExistingAttachments((prev) =>
                                  prev.filter((a) => a.fileId !== att.fileId)
                                );
                              }}
                              className="file-remove-btn"
                            >
                              ×
                            </button>
                          </div>
                        ))}
                      </div>
                    )}

                    <div className="custom-file-input">
                      <label htmlFor="file-upload" className="file-input-label">
                        <i className="fas fa-plus"></i> Add Files
                      </label>
                      <input
                        id="file-upload"
                        type="file"
                        className="file-input-hidden"
                        multiple
                        onChange={(e) =>
                          setNewlySelectedFiles(Array.from(e.target.files))
                        }
                      />
                    </div>
                    {newlySelectedFiles.length > 0 && (
                      <div className="attachment-list newly-selected">
                        {newlySelectedFiles.map((file, index) => (
                          <div
                            key={file.name + index}
                            className="attachment-list-item"
                          >
                            <i className="fas fa-file-upload"></i>
                            <span>{file.name}</span>
                            <button
                              onClick={() => {
                                setNewlySelectedFiles((prev) =>
                                  prev.filter((_, i) => i !== index)
                                );
                              }}
                              className="file-remove-btn"
                            >
                              ×
                            </button>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                )}
              </div>
              <div className="modal-footer">
                <button
                  className="modal-cancel-btn"
                  onClick={() => setIsModalOpen(false)}
                >
                  Cancel
                </button>
                <button className="modal-save-btn" onClick={handleModalSave}>
                  Save
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
        {isConfirmationModalOpen && (
          <div className="modal-overlay" key="confirmation-modal">
            <motion.div
              className="modal-content"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
            >
              <h3 className="modal-title">{confirmationModalConfig.title}</h3>
              <div className="modal-body">
                <div className="confirm-warning-icon">
                  <i className="fas fa-exclamation-triangle"></i>
                </div>
                <p className="modal-description">
                  {confirmationModalConfig.text}
                </p>
              </div>
              <div className="modal-footer">
                <button
                  className="modal-cancel-btn"
                  onClick={() => setIsConfirmationModalOpen(false)}
                >
                  Cancel
                </button>
                <button
                  className="modal-confirm-btn"
                  onClick={() => {
                    confirmationModalConfig.onConfirm();
                    setIsConfirmationModalOpen(false);
                  }}
                >
                  Yes, delete it
                </button>
              </div>
            </motion.div>
          </div>
        )}
        {isFileViewerOpen && (
          <div
            className="modal-overlay"
            key="file-viewer-modal"
            onClick={() => setIsFileViewerOpen(false)}
          >
            <motion.div
              ref={fileViewerRef}
              className="modal-content file-viewer-modal"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              onClick={(e) => e.stopPropagation()}
            >
              <h3 className="modal-title">
                {fileViewerContent.name}
                <button
                  onClick={handleToggleFullscreen}
                  className="modal-fullscreen-btn"
                  title={isFullscreen ? "Exit Fullscreen" : "Enter Fullscreen"}
                >
                  <i
                    className={`fas ${
                      isFullscreen ? "fa-compress" : "fa-expand"
                    }`}
                  ></i>
                </button>
              </h3>
              <div
                className="modal-body file-viewer-body"
                style={{
                  aspectRatio:
                    fileViewerContent.width && fileViewerContent.height
                      ? `${fileViewerContent.width} / ${fileViewerContent.height}`
                      : "auto",
                }}
              >
                {fileViewerContent.type === "loading" && (
                  <div className="loading-spinner"></div>
                )}
                {fileViewerContent.type === "error" && (
                  <p className="modal-error">{fileViewerContent.data}</p>
                )}
                {fileViewerContent.type === "image" && (
                  <img
                    src={fileViewerContent.data}
                    alt={fileViewerContent.name}
                  />
                )}
                {fileViewerContent.type === "iframe" && (
                  <iframe
                    src={fileViewerContent.data}
                    title={fileViewerContent.name}
                    allow="fullscreen"
                  />
                )}
                {fileViewerContent.type === "text" && (
                  <pre>{fileViewerContent.data}</pre>
                )}
              </div>
              <div className="modal-footer">
                <button
                  className="modal-cancel-btn"
                  onClick={() => setIsFileViewerOpen(false)}
                >
                  Close
                </button>
              </div>
            </motion.div>
          </div>
        )}

        {isChangePasswordModalOpen && (
          <motion.div
            className="modal-overlay"
            key="change-password-modal"
            onClick={() => setIsChangePasswordModalOpen(false)}
          >
            <motion.div
              className="modal-content"
              onClick={(e) => e.stopPropagation()}
            >
              <h3 className="modal-title">Change Master Password</h3>
              <div className="modal-body">
                <p className="modal-description">
                  To change your master password, please first enter your
                  current password.
                </p>

                <input
                  type="password"
                  className="modal-input"
                  placeholder="Current Master Password"
                  value={currentPasswordInput}
                  onChange={(e) => setCurrentPasswordInput(e.target.value)}
                  autoFocus
                />

                <input
                  type="password"
                  className="modal-input"
                  placeholder="New Master Password"
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                />

                <input
                  type="password"
                  className="modal-input"
                  placeholder="Confirm New Password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                />

                {changePasswordError && (
                  <p className="modal-error">{changePasswordError}</p>
                )}
              </div>
              <div className="modal-footer">
                <button
                  className="modal-cancel-btn"
                  onClick={() => setIsChangePasswordModalOpen(false)}
                >
                  Cancel
                </button>
                <button
                  className="modal-save-btn"
                  onClick={handleChangePassword}
                >
                  Save New Password
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}

      </AnimatePresence>
    </>
  );
}


